import java.io.Reader;
import java.io.StringReader;

import static org.junit.jupiter.api.Assertions.*;

public class Parser_parseInput_Test {

    @Test
    @DisplayName("TC01_O1: parseInput(String, String) delegates to parseInput(Reader, String) and returns placeholder Document")
    public void test_TC01_O1() {
        // Setup: stub HtmlTreeBuilder so that parse(...) returns our placeholderDoc
        Document placeholderDoc = new Document("http://example.com");
        HtmlTreeBuilder stubBuilder = new HtmlTreeBuilder() {
